import re
import numpy as np
from scipy.stats import ttest_rel

def task_func(text1, text2):
    words1 = re.findall(r'\w+', text1)
    words2 = re.findall(r'\w+', text2)

    if len(words1) != len(words2):
        return tuple(np.nan for _ in range(2))

    diff = np.array(words1) - np.array(words2)
    t_stat, p_val = ttest_rel(diff, equal_var=True)

    return tuple([t_stat, p_val])
